/**
 * Async Operation Types
 *
 * Unified types for progress reporting, cancellation, and batch processing
 * across all managers. These types enable consistent async patterns.
 *
 * @module types/async
 */

/**
 * Callback for reporting progress of long-running operations.
 *
 * @param current - Current progress count (e.g., items processed)
 * @param total - Total expected count
 * @param message - Optional status message
 *
 * @example
 * ```typescript
 * const onProgress: ProgressCallback = (current, total, message) => {
 *   console.log(`Progress: ${current}/${total} - ${message}`);
 * };
 * ```
 */
export type ProgressCallback = (current: number, total: number, message?: string) => void;

/**
 * Options for operations that support cancellation.
 *
 * @example
 * ```typescript
 * const controller = new AbortController();
 * await manager.longOperation({ signal: controller.signal });
 * // Later: controller.abort();
 * ```
 */
export interface CancellableOptions {
  /** AbortSignal for cancellation support */
  signal?: AbortSignal;
}

/**
 * Options for operations that support progress reporting.
 */
export interface ProgressOptions {
  /** Callback for progress updates */
  onProgress?: ProgressCallback;
}

/**
 * Combined options for cancellable operations with progress.
 */
export interface AsyncOperationOptions extends CancellableOptions, ProgressOptions {}

/**
 * Options for batch processing operations.
 *
 * @example
 * ```typescript
 * const options: BatchProgressOptions = {
 *   batchSize: 50,
 *   onProgress: (c, t) => console.log(`${c}/${t}`),
 *   signal: controller.signal
 * };
 * ```
 */
export interface BatchProgressOptions extends AsyncOperationOptions {
  /** Number of items to process per batch (default: 50) */
  batchSize?: number;
  /** Delay between batches in ms (default: 0) */
  delayBetweenBatches?: number;
}

/**
 * Result of a cancellable operation.
 */
export interface CancellableResult<T> {
  /** The result value if completed */
  result?: T;
  /** Whether the operation was cancelled */
  cancelled: boolean;
  /** Items processed before cancellation (if applicable) */
  processedCount?: number;
}

/**
 * Check if an AbortSignal is aborted and throw if so.
 *
 * @param signal - AbortSignal to check
 * @param operation - Name of the operation (for error message)
 * @throws {Error} If signal is aborted
 */
export function checkAborted(signal: AbortSignal | undefined, operation: string): void {
  if (signal?.aborted) {
    throw new Error(`${operation} was cancelled`);
  }
}

/**
 * Helper to check cancellation and yield control periodically.
 *
 * @param signal - AbortSignal to check
 * @param operation - Name of the operation
 * @param yieldEvery - Yield control every N items (default: 100)
 * @param current - Current item count
 * @returns Promise that resolves if not cancelled
 */
export async function checkAbortedAndYield(
  signal: AbortSignal | undefined,
  operation: string,
  yieldEvery: number = 100,
  current: number = 0
): Promise<void> {
  checkAborted(signal, operation);
  if (current > 0 && current % yieldEvery === 0) {
    await new Promise(resolve => setImmediate(resolve));
  }
}

