async createEntities(
  entities: Entity[],
  options?: BatchProgressOptions
): Promise<CancellableResult<Entity[]>> {
  // Validate input
  if (!entities || entities.length === 0) {
    return { result: [], cancelled: false, processedCount: 0 };
  }

  checkAborted(options?.signal, 'createEntities');

  const batchSize = options?.batchSize ?? 50;
  const createdEntities: Entity[] = [];
  const graph = await this.storage.getGraphForMutation();
  const timestamp = new Date().toISOString();
  const total = entities.length;

  try {
    for (let i = 0; i < entities.length; i += batchSize) {
      checkAborted(options?.signal, 'createEntities');

      const batch = entities.slice(i, i + batchSize);

      for (const entity of batch) {
        // ... existing validation and creation logic ...
        const newEntity = { ...normalized, createdAt: timestamp, lastModified: timestamp };
        graph.entities.push(newEntity);
        createdEntities.push(newEntity);
      }

      // Report progress
      options?.onProgress?.(Math.min(i + batchSize, total), total, `Created ${createdEntities.length} entities`);

      // Yield control to event loop
      if (i + batchSize < entities.length) {
        await new Promise(resolve => setImmediate(resolve));
      }
    }

    await this.storage.saveGraph(graph);
    return { result: createdEntities, cancelled: false, processedCount: createdEntities.length };
  } catch (error) {
    if (error instanceof Error && error.message.includes('cancelled')) {
      // Save partial progress
      if (createdEntities.length > 0) {
        await this.storage.saveGraph(graph);
      }
      return { result: createdEntities, cancelled: true, processedCount: createdEntities.length };
    }
    throw error;
  }
}

