describe('createEntities with BatchProgressOptions', () => {
  it('should call onProgress during creation', async () => {
    const progressCalls: [number, number][] = [];
    const entities = Array.from({ length: 100 }, (_, i) => ({
      name: `Entity${i}`,
      entityType: 'test',
      observations: []
    }));

    const result = await entityManager.createEntities(entities, {
      batchSize: 25,
      onProgress: (current, total) => progressCalls.push([current, total])
    });

    expect(result.cancelled).toBe(false);
    expect(progressCalls.length).toBeGreaterThanOrEqual(4);
    expect(progressCalls[progressCalls.length - 1][0]).toBe(100);
  });

  it('should stop when signal is aborted', async () => {
    const controller = new AbortController();
    const entities = Array.from({ length: 200 }, (_, i) => ({
      name: `Entity${i}`,
      entityType: 'test',
      observations: []
    }));

    // Abort after first batch
    setTimeout(() => controller.abort(), 10);

    const result = await entityManager.createEntities(entities, {
      batchSize: 25,
      signal: controller.signal
    });

    expect(result.cancelled).toBe(true);
    expect(result.processedCount).toBeLessThan(200);
  });
});

